96	  it("2 runes + 1 moonstone yield base premium 75 G (different types, no block)", () => {
97	    expect(
98	      quote({
99	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
100	        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
101	      })
102	    ).toBe(88);
103	  });
104	  it.todo("3 runes + 3 moonstones yield base premium 120 G (two separate blocks)");
105	
106	  // ===== Quote: item-specific modifiers =====
107	  it.todo("cursed sword adds 50% surcharge on item base (cursed sword alone: 100 + 50 = 150 base)");
108	  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge on item base");
109	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
110	  it.todo("cursed sword with enchantment 5 stacks both surcharges on item base");
111	
112	  // ===== Quote: modifier scope on multi-item policies =====
113	  it.todo("policy with cursed sword + plain amulet: cursed surcharge applies only to cursed item base (newcomer total 231 G)");
114	
115	  // ===== Quote: policy-wide modifiers =====
116	  it.todo("long-standing customer (exactly 2 years) receives 20% loyalty discount on policy base");
117	  it.todo("first insurance (newcomer, no prior contracts) adds 10% surcharge on policy base");
118	  it.todo("follow-up contract gives 15% discount on policy base");
119	
120	  // ===== Quote: rounding in MHPCO's favor =====
121	  it.todo("premium calculation that yields 197.5 G rounds up to 198 G");
122	  it.todo("intermediate amounts kept as fractions; only final premium is rounded");
123	
124	  // ===== Quote: integration examples from spec =====
125	  it.todo("newcomer with cursed sword (steel, enchantment 3) yields premium 165 G");
126	  it.todo("long-standing (3 yrs) customer's second quote with cursed sword (enchantment 7) yields premium 160 G");
127	
128	  // ===== Claim: basic deductible =====
129	  it.todo("regular sword (steel, enchantment 3), damage 500 G yields payout 400 G (full minus 100 deductible)");
130	  it.todo("rune (insurance value 250 G), damage 200 G yields payout 100 G (full minus deductible, no special clauses)");
131	
132	  // ===== Claim: special clauses =====
133	  it.todo("steel sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible)");
134	  it.todo("dragon-material sword enchantment 5, damage 800 G yields payout 700 G (full minus deductible)");
135	  it.todo("dragon-material sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible — both clauses apply)");
136	  it.todo("dragon-material sword exactly enchantment 8, damage 1000 G yields payout 400 G (50% then deductible)");
137	
138	  // ===== Claim: deductible per damage event (multi-item incident) =====
139	  it.todo("dragon attack damages sword (500 G) and amulet (300 G): payout 600 G (deductible per item)");
140	
141	  // ===== Claim: rounding =====
142	  it.todo("payout calculation that yields 350.5 G rounds down to 350 G");
143	
144	  // ===== Claim: insurance sum and cap =====
145	  it.todo("policy of sword + amulet: insurance sum 1600 G, cap 3200 G");
146	  it.todo("policy of sword + 3 runes (a block): insurance sum 1750 G (block discount affects premium only)");
147	  it.todo("cursed sword: cap 2000 G based on unmodified insurance value (premium modifiers do not raise cap)");
148	
149	  // ===== Claim: cap exhaustion across successive claims =====
150	  it.todo("sword (cap 2000 G), first claim 1500 G yields payout 1400 G, remainingCap 600 G");
151	  it.todo("sword (cap 2000 G), after first 1500 G claim, second 1500 G claim yields payout 600 G, remainingCap 0 G");
152	
153	  // ===== Claim: multiple items of same type =====
154	  it.todo("policy covers two swords: insurance sum 2000 G, cap 4000 G");
155	  it.todo("dragon attack damages both insured swords: each entry treated separately with own deductible");
156	
157	  // ===== CLI / scenario integration =====
158	  it.todo("scenario with quote then claim returns results array of length 2 with {premium} and {payout, remainingCap}");
159	
160	  // ===== Error cases =====
161	  it.todo("quote with unknown item type (e.g. broomstick) causes CLI to exit non-zero with stderr error");
162	  it.todo("claim referencing damage to an item not in the policy causes CLI to exit non-zero with stderr error");
163	  it.todo("claim with damages array containing more entries of a type than insured causes CLI to exit non-zero");
164	  it.todo("claim with negative damage amount causes CLI to exit non-zero with stderr error");
165	});
