3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const RUNE_BLOCK_PREMIUM = 60;
23	
24	const ITEM_BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	function sumItemBasePremiums(items: Item[]): number {
34	  return items.reduce(
35	    (sum, item) => sum + ITEM_BASE_PREMIUMS[item.type],
36	    0
37	  );
38	}
39	
40	function isBlockOfThreeRunes(items: Item[]): boolean {
41	  return items.length === 3 && items.every((item) => item.type === "rune");
42	}
43	
44	function calculatePolicyBase(items: Item[]): number {
45	  if (isBlockOfThreeRunes(items)) {
46	    return RUNE_BLOCK_PREMIUM;
47	  }
48	  return sumItemBasePremiums(items);
49	}
50	
51	export function quote(input: QuoteInput): number {
52	  const policyBase = calculatePolicyBase(input.items);
53	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
54	  return Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
55	}
